expected_value <- function(outcomes, probs) {
  if (abs(sum(probs) - 1) > 1e-6) stop('Probabilities must sum to 1')
  EV <- sum(probs * outcomes)
  cat('E[X] =', paste(probs, '*', outcomes, collapse=' + '), '=', EV, '\n')
  return(EV)
}

# Farmer fertilizer example
