# Numerical derivatives
num_deriv <- function(f, x, h = 1e-6) (f(x+h) - f(x-h)) / (2*h)
num_deriv2 <- function(f, x, h = 1e-4) (f(x+h) - 2*f(x) + f(x-h)) / (h^2)

# Arrow-Pratt measures
ara <- function(u_fn, x) {
  u1 <- num_deriv(u_fn, x)
  u2 <- num_deriv2(u_fn, x)
  -u2 / u1
}

rra <- function(u_fn, x) {
  x * ara(u_fn, x)
}

